option.value:
* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
  font-family: "Inter", sans-serif;
  text-decoration: none;
  list-style: none;
  scroll-behavior: smooth;
}

/* variables */
:root {
  --text-color: #e5e5e5;
  --bg-color: #1a0f0f;
  --second-bg-color: #221515;
  --main-color: #8B0000;
  --other-color: #a1a1aa;
  --h1-font: 4rem;
  --h2-font: 2.8rem;
  --p-font: 1rem;
}

/* light mode override */
body.light-mode {
  --text-color: #111111;
  --bg-color: #ffffff;
  --second-bg-color: #f3f3f3;
  --main-color: #8B0000;
  --other-color: #555555;
  /* gradient lebih cerah untuk light mode */
  background: linear-gradient(180deg, #ffffff 0%, #f3f3f3 100%);
}

/* body with gradient background */
body {
  color: var(--text-color);
  background: linear-gradient(180deg, #1a0f0f 0%, #0f0f0f 100%);
}

/* global header / navbar */
header {
  position: fixed;
  width: 100%;
  top: 0;
  right: 0;
  z-index: 1000;
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 30px 10%;
  background: transparent;
  transition: all 0.4s ease;
}
header.sticky {
  background: var(--bg-color);
  padding: 15px 10%;
  box-shadow: 0 4px 20px rgba(0,0,0,0.3);
}
.logo {
  display: flex;
  align-items: center;
  gap: 10px;
  font-size: 24px;
  font-weight: 700;
  color: var(--text-color);
}
.logo-box {
  background: var(--main-color);
  color: #ffffff;
  width: 38px;
  height: 38px;
  border-radius: 8px;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 22px;
}
.navlist {
  display: flex;
}
.navlist a {
  font-size: var(--p-font);
  font-weight: 500;
  color: var(--text-color);
  margin: 0 18px;
  transition: 0.3s;
}
.navlist a:hover,
.navlist a.active {
  color: var(--main-color);
}
.header-btns {
  display: flex;
  align-items: center;
  gap: 15px;
}
.h-btn {
  padding: 10px 22px;
  border-radius: 8px;
  border: 1.5px solid var(--main-color);
  color: var(--text-color);
  font-size: 0.9rem;
  font-weight: 500;
  background: transparent;
  transition: 0.3s;
}
.h-btn:hover {
  background: var(--main-color);
  color: #ffffff;
}
.theme-toggle {
  font-size: 22px;
  cursor: pointer;
  color: var(--text-color);
  transition: 0.3s;
}
.theme-toggle:hover {
  color: var(--main-color);
  transform: scale(1.05);
}
#menu-icon {
  font-size: 32px;
  cursor: pointer;
  display: none;
  color: var(--text-color);
}

/* hero section (index) */
section {
  padding: 120px 10% 80px;
}
.hero {
  min-height: 100vh;
  display: flex;
  flex-direction: column;
  justify-content: center;
}
.hero-wrapper {
  display: grid;
  grid-template-columns: 1.2fr 1fr;
  align-items: center;
  gap: 40px;
}
.welcome-badge {
  display: inline-block;
  padding: 4px 16px;
  border-radius: 20px;
  border: 1px solid var(--main-color);
  color: var(--main-color);
  font-size: 0.8rem;
  font-weight: 600;
  margin-bottom: 18px;
}
.hero-text h1 {
  font-size: var(--h1-font);
  line-height: 1.1;
  margin-bottom: 18px;
}
.hero-text h1 span {
  color: var(--main-color);
}
.hero-text p {
  font-size: var(--p-font);
  color: var(--other-color);
  line-height: 1.7;
  max-width: 520px;
  margin-bottom: 30px;
}
.hero-btns {
  display: flex;
  align-items: center;
  gap: 25px;
}
.btn {
  padding: 13px 28px;
  border-radius: 10px;
  background: var(--main-color);
  color: #ffffff;
  font-size: 0.95rem;
  font-weight: 600;
  transition: 0.3s;
}
.btn:hover {
  opacity: 0.85;
  transform: translateY(-2px);
}
.view-work {
  color: var(--text-color);
  font-weight: 600;
  display: flex;
  align-items: center;
  gap: 8px;
}

/* hero image side */
.hero-img {
  position: relative;
  display: flex;
  justify-content: center;
}
.img-container {
  position: relative;
  width: 360px;
  height: 410px;
  z-index: 5;
}
.img-container img {
  width: 100%;
  height: 100%;
  object-fit: cover;
  background: var(--main-color);
}
.img-outline {
  position: absolute;
  width: 100%;
  height: 100%;
  border: 3px solid var(--text-color);
  top: 28px;
  left: -28px;
  z-index: -1;
}
.social-float {
  position: absolute;
  right: -60px;
  top: 50%;
  transform: translateY(-50%);
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 18px;
}
.social-float p {
  writing-mode: vertical-rl;
  font-size: 13px;
  color: var(--other-color);
  letter-spacing: 1px;
}
.social-float a {
  color: var(--main-color);
  font-size: 20px;
}

/* hero stats */
.hero-stats {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-top: 70px;
  padding-top: 45px;
  border-top: 1px solid rgba(128,128,128,0.3);
}
.stat-item h2 {
  font-size: 3.2rem;
  color: var(--main-color);
}
.stat-item p {
  color: var(--other-color);
  font-size: 1.05rem;
}

/* shared section helpers */
.center-text {
  text-align: center;
  margin-bottom: 4rem;
}
.center-text h2 {
  font-size: var(--h2-font);
}
.center-text span {
  color: var(--main-color);
}

/* services / generic cards */
.box-grid,
.services-content,
.Portfolio-content {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(300px, auto));
  gap: 2rem;
}
.card,
.box,
.row {
  background: var(--second-bg-color);
  border-radius: 20px;
  padding: 40px 28px;
  transition: 0.4s;
}
.card:hover,
.box:hover,
.row:hover {
  transform: translateY(-8px);
  border: 1px solid var(--main-color);
}

/* footer global */
.footer {
  padding: 40px 10%;
  text-align: center;
  background: var(--second-bg-color);
  color: var(--other-color);
  margin-top: 40px;
}

/* override khusus untuk card / blog di light mode */
body.light-mode .card,
body.light-mode .box,
body.light-mode .row,
body.light-mode .portfolio-card,
body.light-mode .cert-card {
  background: #ffffff;
  border-color: rgba(0, 0, 0, 0.06);
}

body.light-mode .blog-card {
  background: #ffffff;
  border-color: rgba(0, 0, 0, 0.06);
}

body.light-mode .blog-card::before {
  background: radial-gradient(circle, rgba(139, 0, 0, 0.07) 0%, transparent 60%);
}

/* portfolio page cards */
.portfolio-container {
  max-width: 1100px;
  margin: 0 auto;
  display: flex;
  flex-direction: column;
  gap: 40px;
}
.portfolio-card {
  background: rgba(255,255,255,0.02);
  border-radius: 30px;
  border: 1px solid rgba(255,255,255,0.08);
  display: grid;
  grid-template-columns: 1fr 1fr;
  overflow: hidden;
  transition: 0.4s;
}
.portfolio-card:hover {
  transform: translateY(-8px);
  border-color: var(--main-color);
  box-shadow: 0 18px 38px rgba(0,0,0,0.35);
}
.card-info {
  padding: 50px;
  display: flex;
  flex-direction: column;
  justify-content: center;
}
.card-tag {
  font-size: 0.75rem;
  text-transform: uppercase;
  letter-spacing: 2px;
  color: var(--other-color);
  margin-bottom: 12px;
}
.card-info h2 {
  font-size: 2rem;
  margin-bottom: 18px;
}
.card-info ul {
  margin-bottom: 25px;
}
.card-info ul li {
  color: var(--other-color);
  margin-bottom: 8px;
  display: flex;
  align-items: center;
  gap: 8px;
}
.card-info ul li i {
  color: var(--main-color);
}
.view-case-btn {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  padding: 10px 22px;
  border-radius: 10px;
  background: #ffffff;
  color: #000000;
  font-weight: 600;
  font-size: 0.9rem;
  transition: 0.3s;
}
.view-case-btn:hover {
  background: var(--main-color);
  color: #ffffff;
}
.card-img {
  padding: 35px;
  display: flex;
  align-items: center;
  justify-content: center;
  background: radial-gradient(circle at top, rgba(255,51,51,0.15), transparent 60%);
}
.card-img img {
  width: 100%;
  height: 330px;
  object-fit: cover;
  border-radius: 20px;
}

/* CV page layout */
.cv-container {
  display: grid;
  grid-template-columns: 260px 1fr;
  gap: 40px;
  padding: 150px 10% 80px;
  max-width: 1400px;
  margin: 0 auto;
}
.cv-sidebar {
  position: sticky;
  top: 120px;
  height: fit-content;
}
.cv-sidebar ul li {
  margin-bottom: 14px;
}
.cv-sidebar ul li a {
  color: var(--other-color);
  font-size: 0.9rem;
  font-weight: 500;
  padding: 8px 14px;
  border-left: 2px solid transparent;
  display: block;
  transition: 0.3s;
}
.cv-sidebar ul li a:hover {
  color: var(--main-color);
  border-left-color: var(--main-color);
  /* Background hover lebih halus dengan tint merah */
  background: rgba(139, 0, 0, 0.1);
  border-radius: 0 8px 8px 0;
}
.cv-content {
  /* Gradasi Gelap ke Merah Sangat Tua (Night Mode) */
  background: linear-gradient(145deg, rgba(34, 21, 21, 0.9) 0%, rgba(15, 10, 10, 0.95) 100%);
  border-radius: 24px;
  /* Border merah transparan agar terlihat 'menyala' tipis */
  border: 1px solid rgba(139, 0, 0, 0.3);
  padding: 50px;
  /* Shadow merah halus untuk kedalaman */
  box-shadow: 0 20px 50px rgba(0, 0, 0, 0.5), 0 0 15px rgba(139, 0, 0, 0.05);
  backdrop-filter: blur(10px);
}
.cv-header {
  display: flex;
  justify-content: space-between;
  align-items: flex-start;
  margin-bottom: 35px;
  padding-bottom: 25px;
  border-bottom: 1px solid rgba(255,255,255,0.1);
}
.cv-header h1 {
  font-size: 2.6rem;
  margin-bottom: 8px;
}
.cv-header p {
  color: var(--main-color);
  font-weight: 600;
}
.pdf-icon {
  font-size: 36px;
  color: var(--main-color);
  cursor: pointer;
}
.cv-section {
  margin-bottom: 40px;
}
.cv-section h2 {
  font-size: 1.7rem;
  margin-bottom: 20px;
  padding-left: 12px;
  border-left: 4px solid var(--main-color);
}
.basics-grid {
  display: grid;
  grid-template-columns: 150px 1fr;
  gap: 15px;
  /* Warna kotak info dasar: Putih transparan dengan tint merah */
  background: rgba(255, 255, 255, 0.03);
  padding: 25px;
  border-radius: 15px;
  border: 1px solid rgba(255, 255, 255, 0.05);
}

body.light-mode .cv-sidebar ul li a:hover {
  background: rgba(139, 0, 0, 0.05);
}

body.light-mode .basics-grid {
  /* Kotak info di light mode: Merah pucat bersih */
  background: rgba(139, 0, 0, 0.02);
  border: 1px solid rgba(139, 0, 0, 0.08);
}

/* Penyesuaian Light Mode untuk CV */
body.light-mode .cv-content {
  /* Gradasi Putih ke Merah Sangat Muda */
  background: linear-gradient(145deg, #ffffff 0%, #fff5f5 100%);
  border: 1px solid rgba(139, 0, 0, 0.1);
  box-shadow: 0 20px 40px rgba(139, 0, 0, 0.05);
  color: #111;
}

.cv-sidebar ul li a {
  transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
}

.cv-content h2 {
  /* Memberikan sedikit glow pada judul section */
  text-shadow: 0 0 10px rgba(139, 0, 0, 0.2);
}

.basics-grid span:nth-child(odd) {
  font-weight: 600;
  color: var(--other-color);
}
.timeline-item {
  margin-bottom: 26px;
}
.timeline-header {
  display: flex;
  justify-content: space-between;
  margin-bottom: 6px;
}
.timeline-title {
  font-weight: 700;
}
.timeline-subtitle {
  color: var(--main-color);
  font-size: 0.95rem;
  margin-bottom: 6px;
  display: block;
}
/* Timeline Badge (Date) */
timeline-date {
  background: var(--main-color); /* Merah marun kamu */
  color: #ffffff;               /* Ganti dari hitam ke putih */
  padding: 4px 14px;            /* Sedikit lebih lebar agar lega */
  border-radius: 20px;
  font-size: 0.8rem;
  font-weight: 700;             /* Tebalkan sedikit agar makin jelas */
  display: inline-block;
  box-shadow: 0 4px 12px rgba(139, 0, 0, 0.3); /* Shadow merah halus */
  letter-spacing: 0.5px;
}

/* Jika ingin transisi halus saat hover */
.timeline-item:hover .timeline-date {
  transform: scale(1.05);
  transition: 0.3s;
}

.timeline-content {
  color: var(--other-color);
  font-size: 0.9rem;
}
.timeline-content li {
  margin-left: 18px;
  list-style: disc;
  margin-bottom: 5px;
}
.skills-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 24px;
}
.skill-cat h4 {
  margin-bottom: 10px;
  color: var(--main-color);
}
.skill-list {
  color: var(--other-color);
  font-size: 0.95rem;
}

/* certifications page */
.cert-header {
  text-align: center;
  margin-bottom: 60px;
}
.cert-header span {
  text-transform: uppercase;
  font-size: 0.75rem;
  letter-spacing: 4px;
  color: var(--main-color);
  font-weight: 600;
}
.cert-header h1 {
  font-size: 3rem;
  margin: 15px 0;
}
.cert-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(320px, 1fr));
  gap: 24px;
  max-width: 1200px;
  margin: 0 auto;
}
.cert-card {
  background: rgba(255,255,255,0.02);
  border-radius: 24px;
  border: 1px solid rgba(255,51,51,0.15);
  padding: 26px;
  display: flex;
  flex-direction: column;
  gap: 16px;
  transition: 0.3s;
}
.cert-card:hover {
  transform: translateY(-8px);
  border-color: var(--main-color);
  box-shadow: 0 16px 32px rgba(0,0,0,0.3);
}
.cert-img-box {
  width: 100%;
  height: 220px;
  border-radius: 16px;
  overflow: hidden;
  background: var(--second-bg-color);
}
.cert-img-box img {
  width: 100%;
  height: 100%;
  object-fit: cover;
  transition: 0.4s;
}
.cert-card:hover .cert-img-box img {
  transform: scale(1.05);
}
.cert-info h3 {
  font-size: 1.4rem;
  margin-bottom: 6px;
  display: flex;
  align-items: center;
  gap: 8px;
}
.cert-info h3 i {
  color: var(--main-color);
}
.cert-info p {
  color: var(--other-color);
  font-size: 0.95rem;
}

/* blog page */
.blog-header {
  text-align: center;
  margin-bottom: 60px;
}
.blog-header span {
  text-transform: uppercase;
  font-size: 0.75rem;
  letter-spacing: 4px;
  color: var(--main-color);
  font-weight: 600;
}
.blog-header h1 {
  font-size: 3rem;
  margin: 15px 0;
}
.blog-header p {
  color: var(--other-color);
}
.blog-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(320px, 1fr));
  gap: 26px;
  max-width: 1200px;
  margin: 0 auto;
}
.blog-card {
  background: #130b0b;
  border-radius: 24px;
  border: 1px solid rgba(255,51,51,0.18);
  padding: 38px;
  min-height: 320px;
  display: flex;
  flex-direction: column;
  justify-content: space-between;
  position: relative;
  overflow: hidden;
  transition: 0.35s;
}
.blog-card::before {
  content: '';
  position: absolute;
  top: -50%;
  left: -50%;
  width: 200%;
  height: 200%;
  background: radial-gradient(circle, rgba(255,51,51,0.06) 0%, transparent 60%);
}
.blog-card h2 {
  font-size: 1.7rem;
  line-height: 1.3;
}
.blog-card:hover {
  transform: translateY(-8px);
  border-color: var(--main-color);
  box-shadow: 0 20px 40px rgba(0,0,0,0.35);
}
.blog-card:hover h2 {
  color: var(--main-color);
}
.blog-icon {
  width: 46px;
  height: 46px;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 22px;
}

/* search modal */
.search-modal {
  position: fixed;
  inset: 0;
  background: rgba(0,0,0,0.8);
  display: none;
  align-items: center;
  justify-content: center;
  z-index: 1200;
}
.search-modal.active {
  display: flex;
}
.search-box {
  background: #1a1a1a;
  padding: 20px;
  border-radius: 12px;
  width: 90%;
  max-width: 420px;
}
.search-box input {
  width: 100%;
  padding: 10px 12px;
  border-radius: 6px;
  border: none;
  outline: none;
  margin-bottom: 12px;
}
.search-box ul li {
  margin-bottom: 6px;
}
.search-box ul li a {
  color: #ffffff;
  font-size: 0.95rem;
}

/* agar modal ikut light mode */
body.light-mode .search-box {
  background: #ffffff;
}
body.light-mode .search-box input {
  background: #f3f3f3;
  color: #111111;
}
body.light-mode .search-box ul li a {
  color: #111111;
}

/* responsive */
@media (max-width: 1200px) {
  section,
  .page-content {
    padding: 120px 6% 70px;
  }
  header,
  header.sticky {
    padding: 20px 6%;
  }
  .hero-wrapper {
    grid-template-columns: 1fr;
    text-align: center;
  }
  .hero-text p {
    margin-left: auto;
    margin-right: auto;
  }
  .hero-btns {
    justify-content: center;
  }
  .hero-img {
    order: -1;
    margin-bottom: 50px;
  }
  .social-float {
    display: none;
  }
  .hero-stats {
    flex-wrap: wrap;
    justify-content: center;
    gap: 30px;
  }
  .cv-container {
    padding: 140px 6% 70px;
  }
}
@media (max-width: 950px) {
  #menu-icon {
    display: block;
  }
  .navlist {
    position: fixed;
    top: 80px;
    right: -100%;
    width: 260px;
    height: calc(100vh - 80px);
    background: var(--second-bg-color);
    flex-direction: column;
    padding: 30px 20px;
    transition: 0.4s;
  }
  .navlist a {
    display: block;
    margin: 10px 0;
    font-size: 1.05rem;
  }
  .navlist.active {
    right: 0;
  }
  .cv-container {
    grid-template-columns: 1fr;
  }
  .cv-sidebar {
    display: none;
  }
  .cv-content {
    padding: 30px 24px;
  }
}
@media (max-width: 640px) {
  :root {
    --h1-font: 3rem;
    --h2-font: 2.1rem;
  }
  .card,
  .box,
  .row {
    padding: 30px 22px;
  }
  .portfolio-card {
    grid-template-columns: 1fr;
  }
  .card-info {
    padding: 30px 22px;
  }
  .card-img {
    padding: 26px 22px;
  }
  .blog-card {
    padding: 30px 22px;
  }
}

* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
  font-family: "Inter", sans-serif;
  text-decoration: none;
  list-style: none;
  scroll-behavior: smooth;
}

/* variables */
:root {
  --text-color: #e5e5e5;
  --bg-color: #1a0f0f;
  --second-bg-color: #221515;
  --main-color: #8B0000;
  --other-color: #a1a1aa;
  --h1-font: 4rem;
  --h2-font: 2.8rem;
  --p-font: 1rem;
}

/* light mode override */
body.light-mode {
  --text-color: #111111;
  --bg-color: #ffffff;
  --second-bg-color: #f3f3f3;
  --main-color: #8B0000;
  --other-color: #555555;
  /* gradient lebih cerah untuk light mode */
  background: linear-gradient(180deg, #ffffff 0%, #f3f3f3 100%);
}

/* body with gradient background */
body {
  color: var(--text-color);
  background: linear-gradient(180deg, #1a0f0f 0%, #0f0f0f 100%);
}

/* global header / navbar */
header {
  position: fixed;
  width: 100%;
  top: 0;
  right: 0;
  z-index: 1000;
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 30px 10%;
  background: transparent;
  transition: all 0.4s ease;
}
header.sticky {
  background: var(--bg-color);
  padding: 15px 10%;
  box-shadow: 0 4px 20px rgba(0,0,0,0.3);
}
.logo {
  display: flex;
  align-items: center;
  gap: 10px;
  font-size: 24px;
  font-weight: 700;
  color: var(--text-color);
}
.logo-box {
  background: var(--main-color);
  color: #ffffff;
  width: 38px;
  height: 38px;
  border-radius: 8px;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 22px;
}
.navlist {
  display: flex;
}
.navlist a {
  font-size: var(--p-font);
  font-weight: 500;
  color: var(--text-color);
  margin: 0 18px;
  transition: 0.3s;
}
.navlist a:hover,
.navlist a.active {
  color: var(--main-color);
}
.header-btns {
  display: flex;
  align-items: center;
  gap: 15px;
}
.h-btn {
  padding: 10px 22px;
  border-radius: 8px;
  border: 1.5px solid var(--main-color);
  color: var(--text-color);
  font-size: 0.9rem;
  font-weight: 500;
  background: transparent;
  transition: 0.3s;
}
.h-btn:hover {
  background: var(--main-color);
  color: #ffffff;
}
.theme-toggle {
  font-size: 22px;
  cursor: pointer;
  color: var(--text-color);
  transition: 0.3s;
}
.theme-toggle:hover {
  color: var(--main-color);
  transform: scale(1.05);
}
#menu-icon {
  font-size: 32px;
  cursor: pointer;
  display: none;
  color: var(--text-color);
}

/* section & page container */
section {
  padding: 120px 10% 80px;
}

/* tambahkan container global untuk halaman seperti portfolio, blog, repository */
.page-content {
  padding: 150px 10% 80px;
  max-width: 1400px;
  margin: 0 auto;
}

/* hero section (index) */
.hero {
  min-height: 100vh;
  display: flex;
  flex-direction: column;
  justify-content: center;
}
.hero-wrapper {
  display: grid;
  grid-template-columns: 1.2fr 1fr;
  align-items: center;
  gap: 40px;
}
.welcome-badge {
  display: inline-block;
  padding: 4px 16px;
  border-radius: 20px;
  border: 1px solid var(--main-color);
  color: var(--main-color);
  font-size: 0.8rem;
  font-weight: 600;
  margin-bottom: 18px;
}
.hero-text h1 {
  font-size: var(--h1-font);
  line-height: 1.1;
  margin-bottom: 18px;
}
.hero-text h1 span {
  color: var(--main-color);
}
.hero-text p {
  font-size: var(--p-font);
  color: var(--other-color);
  line-height: 1.7;
  max-width: 520px;
  margin-bottom: 30px;
}
.hero-btns {
  display: flex;
  align-items: center;
  gap: 25px;
}
.btn {
  padding: 13px 28px;
  border-radius: 10px;
  background: var(--main-color);
  color: #ffffff;
  font-size: 0.95rem;
  font-weight: 600;
  transition: 0.3s;
}
.btn:hover {
  opacity: 0.85;
  transform: translateY(-2px);
}
.view-work {
  color: var(--text-color);
  font-weight: 600;
  display: flex;
  align-items: center;
  gap: 8px;
}

/* hero image side */
.hero-img {
  position: relative;
  display: flex;
  justify-content: center;
}
.img-container {
  position: relative;
  width: 360px;
  height: 410px;
  z-index: 5;
}
.img-container img {
  width: 100%;
  height: 100%;
  object-fit: cover;
  background: var(--main-color);
}
.img-outline {
  position: absolute;
  width: 100%;
  height: 100%;
  border: 3px solid var(--text-color);
  top: 28px;
  left: -28px;
  z-index: -1;
}
.social-float {
  position: absolute;
  right: -60px;
  top: 50%;
  transform: translateY(-50%);
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 18px;
}
.social-float p {
  writing-mode: vertical-rl;
  font-size: 13px;
  color: var(--other-color);
  letter-spacing: 1px;
}
.social-float a {
  color: var(--main-color);
  font-size: 20px;
}

/* hero stats */
.hero-stats {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-top: 70px;
  padding-top: 45px;
  border-top: 1px solid rgba(128,128,128,0.3);
}
.stat-item h2 {
  font-size: 3.2rem;
  color: var(--main-color);
}
.stat-item p {
  color: var(--other-color);
  font-size: 1.05rem;
}

/* shared section helpers */
.center-text {
  text-align: center;
  margin-bottom: 4rem;
}
.center-text h2 {
  font-size: var(--h2-font);
}
.center-text span {
  color: var(--main-color);
}

/* services / generic cards */
.box-grid,
.services-content,
.Portfolio-content {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(300px, auto));
  gap: 2rem;
}
.card,
.box,
.row {
  background: var(--second-bg-color);
  border-radius: 20px;
  padding: 40px 28px;
  transition: 0.4s;
}
.card:hover,
.box:hover,
.row:hover {
  transform: translateY(-8px);
  border: 1px solid var(--main-color);
}

/* footer global */
.footer {
  padding: 40px 10%;
  text-align: center;
  background: var(--second-bg-color);
  color: var(--other-color);
  margin-top: 40px;
}

/* override khusus untuk card / blog di light mode */
body.light-mode .card,
body.light-mode .box,
body.light-mode .row,
body.light-mode .portfolio-card,
body.light-mode .cert-card {
  background: #ffffff;
  border-color: rgba(0, 0, 0, 0.06);
}

body.light-mode .blog-card {
  background: #ffffff;
  border-color: rgba(0, 0, 0, 0.06);
}

body.light-mode .blog-card::before {
  background: radial-gradient(circle, rgba(139, 0, 0, 0.07) 0%, transparent 60%);
}

/* portfolio page cards */
.portfolio-container {
  max-width: 1100px;
  margin: 0 auto;
  display: flex;
  flex-direction: column;
  gap: 40px;
}
.portfolio-card {
  background: rgba(255,255,255,0.02);
  border-radius: 30px;
  border: 1px solid rgba(255,255,255,0.08);
  display: grid;
  grid-template-columns: 1fr 1fr;
  overflow: hidden;
  transition: 0.4s;
}
.portfolio-card:hover {
  transform: translateY(-8px);
  border-color: var(--main-color);
  box-shadow: 0 18px 38px rgba(0,0,0,0.35);
}
.card-info {
  padding: 50px;
  display: flex;
  flex-direction: column;
  justify-content: center;
}
.card-tag {
  font-size: 0.75rem;
  text-transform: uppercase;
  letter-spacing: 2px;
  color: var(--other-color);
  margin-bottom: 12px;
}
.card-info h2 {
  font-size: 2rem;
  margin-bottom: 18px;
}
.card-info ul {
  margin-bottom: 25px;
}
.card-info ul li {
  color: var(--other-color);
  margin-bottom: 8px;
  display: flex;
  align-items: center;
  gap: 8px;
}
.card-info ul li i {
  color: var(--main-color);
}
.view-case-btn {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  padding: 10px 22px;
  border-radius: 10px;
  background: #ffffff;
  color: #000000;
  font-weight: 600;
  font-size: 0.9rem;
  transition: 0.3s;
}
.view-case-btn:hover {
  background: var(--main-color);
  color: #ffffff;
}
.card-img {
  padding: 35px;
  display: flex;
  align-items: center;
  justify-content: center;
  background: radial-gradient(circle at top, rgba(255,51,51,0.15), transparent 60%);
}
.card-img img {
  width: 100%;
  height: 330px;
  object-fit: cover;
  border-radius: 20px;
}

/* CV page layout */
.cv-container {
  display: grid;
  grid-template-columns: 260px 1fr;
  gap: 40px;
  padding: 150px 10% 80px;
  max-width: 1400px;
  margin: 0 auto;
}
.cv-sidebar {
  position: sticky;
  top: 120px;
  height: fit-content;
}
.cv-sidebar ul li {
  margin-bottom: 14px;
}
.cv-sidebar ul li a {
  color: var(--other-color);
  font-size: 0.9rem;
  font-weight: 500;
  padding: 8px 14px;
  border-left: 2px solid transparent;
  display: block;
  transition: 0.3s;
}
.cv-sidebar ul li a:hover {
  color: var(--main-color);
  border-left-color: var(--main-color);
  /* Background hover lebih halus dengan tint merah */
  background: rgba(139, 0, 0, 0.1);
  border-radius: 0 8px 8px 0;
}
.cv-content {
  /* Gradasi Gelap ke Merah Sangat Tua (Night Mode) */
  background: linear-gradient(145deg, rgba(34, 21, 21, 0.9) 0%, rgba(15, 10, 10, 0.95) 100%);
  border-radius: 24px;
  /* Border merah transparan agar terlihat 'menyala' tipis */
  border: 1px solid rgba(139, 0, 0, 0.3);
  padding: 50px;
  /* Shadow merah halus untuk kedalaman */
  box-shadow: 0 20px 50px rgba(0, 0, 0, 0.5), 0 0 15px rgba(139, 0, 0, 0.05);
  backdrop-filter: blur(10px);
}
.cv-header {
  display: flex;
  justify-content: space-between;
  align-items: flex-start;
  margin-bottom: 35px;
  padding-bottom: 25px;
  border-bottom: 1px solid rgba(255,255,255,0.1);
}
.cv-header h1 {
  font-size: 2.6rem;
  margin-bottom: 8px;
}
.cv-header p {
  color: var(--main-color);
  font-weight: 600;
}
.pdf-icon {
  font-size: 36px;
  color: var(--main-color);
  cursor: pointer;
}
.cv-section {
  margin-bottom: 40px;
}
.cv-section h2 {
  font-size: 1.7rem;
  margin-bottom: 20px;
  padding-left: 12px;
  border-left: 4px solid var(--main-color);
}
.basics-grid {
  display: grid;
  grid-template-columns: 150px 1fr;
  gap: 15px;
  /* Warna kotak info dasar: Putih transparan dengan tint merah */
  background: rgba(255, 255, 255, 0.03);
  padding: 25px;
  border-radius: 15px;
  border: 1px solid rgba(255, 255, 255, 0.05);
}

body.light-mode .cv-sidebar ul li a:hover {
  background: rgba(139, 0, 0, 0.05);
}

body.light-mode .basics-grid {
  /* Kotak info di light mode: Merah pucat bersih */
  background: rgba(139, 0, 0, 0.02);
  border: 1px solid rgba(139, 0, 0, 0.08);
}

/* Penyesuaian Light Mode untuk CV */
body.light-mode .cv-content {
  /* Gradasi Putih ke Merah Sangat Muda */
  background: linear-gradient(145deg, #ffffff 0%, #fff5f5 100%);
  border: 1px solid rgba(139, 0, 0, 0.1);
  box-shadow: 0 20px 40px rgba(139, 0, 0, 0.05);
  color: #111;
}

.cv-sidebar ul li a {
  transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
}

.cv-content h2 {
  /* Memberikan sedikit glow pada judul section */
  text-shadow: 0 0 10px rgba(139, 0, 0, 0.2);
}

.basics-grid span:nth-child(odd) {
  font-weight: 600;
  color: var(--other-color);
}
.timeline-item {
  margin-bottom: 26px;
}
.timeline-header {
  display: flex;
  justify-content: space-between;
  margin-bottom: 6px;
}
.timeline-title {
  font-weight: 700;
}
.timeline-subtitle {
  color: var(--main-color);
  font-size: 0.95rem;
  margin-bottom: 6px;
  display: block;
}
/* Timeline Badge (Date) */
timeline-date {
  background: var(--main-color); /* Merah marun kamu */
  color: #ffffff;               /* Ganti dari hitam ke putih */
  padding: 4px 14px;            /* Sedikit lebih lebar agar lega */
  border-radius: 20px;
  font-size: 0.8rem;
  font-weight: 700;             /* Tebalkan sedikit agar makin jelas */
  display: inline-block;
  box-shadow: 0 4px 12px rgba(139, 0, 0, 0.3); /* Shadow merah halus */
  letter-spacing: 0.5px;
}

/* Jika ingin transisi halus saat hover */
.timeline-item:hover .timeline-date {
  transform: scale(1.05);
  transition: 0.3s;
}

.timeline-content {
  color: var(--other-color);
  font-size: 0.9rem;
}
.timeline-content li {
  margin-left: 18px;
  list-style: disc;
  margin-bottom: 5px;
}
.skills-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 24px;
}
.skill-cat h4 {
  margin-bottom: 10px;
  color: var(--main-color);
}
.skill-list {
  color: var(--other-color);
  font-size: 0.95rem;
}

/* certifications page */
.cert-header {
  text-align: center;
  margin-bottom: 60px;
}
.cert-header span {
  text-transform: uppercase;
  font-size: 0.75rem;
  letter-spacing: 4px;
  color: var(--main-color);
  font-weight: 600;
}
.cert-header h1 {
  font-size: 3rem;
  margin: 15px 0;
}
.cert-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(320px, 1fr));
  gap: 24px;
  max-width: 1200px;
  margin: 0 auto;
}
.cert-card {
  background: rgba(255,255,255,0.02);
  border-radius: 24px;
  border: 1px solid rgba(255,51,51,0.15);
  padding: 26px;
  display: flex;
  flex-direction: column;
  gap: 16px;
  transition: 0.3s;
}
.cert-card:hover {
  transform: translateY(-8px);
  border-color: var(--main-color);
  box-shadow: 0 16px 32px rgba(0,0,0,0.3);
}
.cert-img-box {
  width: 100%;
  height: 220px;
  border-radius: 16px;
  overflow: hidden;
  background: var(--second-bg-color);
}
.cert-img-box img {
  width: 100%;
  height: 100%;
  object-fit: cover;
  transition: 0.4s;
}
.cert-card:hover .cert-img-box img {
  transform: scale(1.05);
}
.cert-info h3 {
  font-size: 1.4rem;
  margin-bottom: 6px;
  display: flex;
  align-items: center;
  gap: 8px;
}
.cert-info h3 i {
  color: var(--main-color);
}
.cert-info p {
  color: var(--other-color);
  font-size: 0.95rem;
}

/* blog page */
.blog-header {
  text-align: center;
  margin-bottom: 60px;
}
.blog-header span {
  text-transform: uppercase;
  font-size: 0.75rem;
  letter-spacing: 4px;
  color: var(--main-color);
  font-weight: 600;
}
.blog-header h1 {
  font-size: 3rem;
  margin: 15px 0;
}
.blog-header p {
  color: var(--other-color);
}
.blog-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(320px, 1fr));
  gap: 26px;
  max-width: 1200px;
  margin: 0 auto;
}
.blog-card {
  background: #130b0b;
  border-radius: 24px;
  border: 1px solid rgba(255,51,51,0.18);
  padding: 38px;
  min-height: 320px;
  display: flex;
  flex-direction: column;
  justify-content: space-between;
  position: relative;
  overflow: hidden;
  transition: 0.35s;
}
.blog-card::before {
  content: '';
  position: absolute;
  top: -50%;
  left: -50%;
  width: 200%;
  height: 200%;
  background: radial-gradient(circle, rgba(255,51,51,0.06) 0%, transparent 60%);
}
.blog-card h2 {
  font-size: 1.7rem;
  line-height: 1.3;
}
.blog-card:hover {
  transform: translateY(-8px);
  border-color: var(--main-color);
  box-shadow: 0 20px 40px rgba(0,0,0,0.35);
}
.blog-card:hover h2 {
  color: var(--main-color);
}
.blog-icon {
  width: 46px;
  height: 46px;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 22px;
}

/* search modal */
.search-modal {
  position: fixed;
  inset: 0;
  background: rgba(0,0,0,0.8);
  display: none;
  align-items: center;
  justify-content: center;
  z-index: 1200;
}
.search-modal.active {
  display: flex;
}
.search-box {
  background: #1a1a1a;
  padding: 20px;
  border-radius: 12px;
  width: 90%;
  max-width: 420px;
}
.search-box input {
  width: 100%;
  padding: 10px 12px;
  border-radius: 6px;
  border: none;
  outline: none;
  margin-bottom: 12px;
}
.search-box ul li {
  margin-bottom: 6px;
}
.search-box ul li a {
  color: #ffffff;
  font-size: 0.95rem;
}

/* agar modal ikut light mode */
body.light-mode .search-box {
  background: #ffffff;
}
body.light-mode .search-box input {
  background: #f3f3f3;
  color: #111111;
}
body.light-mode .search-box ul li a {
  color: #111111;
}

/* =========================
   REPOSITORY PAGE STYLES
   (dipindah dari inline CSS repository.html)
   ========================= */

.repo-stats {
  display: flex;
  justify-content: center;
  gap: 60px;
  text-align: center;
  margin-bottom: 40px;
}
.repo-stats .stat-item h2 {
  font-size: 3rem;
  color: var(--main-color);
}
.repo-stats .stat-item p {
  font-size: 12px;
  text-transform: uppercase;
  letter-spacing: 2px;
  color: var(--other-color);
}

.github-btn-center {
  display: flex;
  justify-content: center;
  margin-bottom: 60px;
}
.gh-profile-btn {
  padding: 12px 25px;
  background: var(--second-bg-color);
  border: 1px solid rgba(255, 51, 51, 0.15);
  color: var(--text-color);
  border-radius: 30px;
  font-size: 14px;
  font-weight: 600;
  display: flex;
  align-items: center;
  gap: 10px;
  transition: 0.3s;
}
.gh-profile-btn:hover {
  background: var(--main-color);
  color: #ffffff;
  border-color: var(--main-color);
}

/* filter & search bar di halaman repository */
.repo-filters {
  background: var(--second-bg-color);
  padding: 30px;
  border-radius: 20px;
  border: 1px solid rgba(255, 51, 51, 0.15);
  display: flex;
  flex-wrap: wrap;
  gap: 20px;
  align-items: center;
  margin-bottom: 50px;
}
.repo-filters .search-input {
  flex: 1;
  min-width: 250px;
  background: var(--bg-color);
  border: 1px solid rgba(255, 51, 51, 0.15);
  padding: 12px 20px;
  border-radius: 12px;
  color: var(--text-color);
  outline: none;
}
.repo-filters .filter-select {
  padding: 12px 15px;
  background: var(--bg-color);
  color: var(--text-color);
  border: 1px solid rgba(255, 51, 51, 0.15);
  border-radius: 12px;
  outline: none;
}
.repo-filters .reset-btn {
  padding: 12px 20px;
  border: 1px solid var(--main-color);
  color: var(--main-color);
  border-radius: 12px;
  font-weight: 600;
  cursor: pointer;
  transition: 0.3s;
  display: flex;
  align-items: center;
  gap: 6px;
}
.repo-filters .reset-btn:hover {
  background: var(--main-color);
  color: #ffffff;
}

/* repo grid / cards */
.repo-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(320px, 1fr));
  gap: 25px;
}
.repo-card {
  background: rgba(255, 255, 255, 0.03);
  border-radius: 20px;
  border: 1px solid rgba(255, 51, 51, 0.15);
  padding: 30px;
  transition: 0.4s;
  display: flex;
  flex-direction: column;
  justify-content: space-between;
  min-height: 220px;
}
.repo-card:hover {
  transform: translateY(-8px);
  border-color: var(--main-color);
  box-shadow: 0 15px 30px rgba(255, 51, 51, 0.1);
}
.repo-title {
  display: flex;
  align-items: center;
  gap: 10px;
  font-size: 1.1rem;
  font-weight: 700;
  margin-bottom: 15px;
  color: var(--text-color);
}
.repo-title i {
  color: var(--main-color);
}
.repo-desc {
  font-size: 14px;
  color: var(--other-color);
  line-height: 1.6;
  margin-bottom: 25px;
}
.repo-meta {
  display: flex;
  justify-content: space-between;
  align-items: center;
  font-size: 12px;
  color: var(--other-color);
}
.lang-tag {
  padding: 4px 10px;
  background: var(--main-color);
  color: #ffffff;
  border-radius: 6px;
  font-weight: 700;
  font-size: 10px;
}

/* responsive */
@media (max-width: 1200px) {
  section,
  .page-content {
    padding: 120px 6% 70px;
  }
  header,
  header.sticky {
    padding: 20px 6%;
  }
  .hero-wrapper {
    grid-template-columns: 1fr;
    text-align: center;
  }
  .hero-text p {
    margin-left: auto;
    margin-right: auto;
  }
  .hero-btns {
    justify-content: center;
  }
  .hero-img {
    order: -1;
    margin-bottom: 50px;
  }
  .social-float {
    display: none;
  }
  .hero-stats {
    flex-wrap: wrap;
    justify-content: center;
    gap: 30px;
  }
  .cv-container {
    padding: 140px 6% 70px;
  }
}

@media (max-width: 950px) {
  #menu-icon {
    display: block;
  }
  .navlist {
    position: fixed;
    top: 80px;
    right: -100%;
    width: 260px;
    height: calc(100vh - 80px);
    background: var(--second-bg-color);
    flex-direction: column;
    padding: 30px 20px;
    transition: 0.4s;
  }
  .navlist a {
    display: block;
    margin: 10px 0;
    font-size: 1.05rem;
  }
  .navlist.active {
    right: 0;
  }
  /* sesuaikan repo stats di mobile */
  .repo-stats {
    gap: 20px;
  }
  .repo-stats .stat-item h2 {
    font-size: 2rem;
  }
}

@media (max-width: 640px) {
  :root {
    --h1-font: 3rem;
    --h2-font: 2.1rem;
  }
  .card,
  .box,
  .row {
    padding: 30px 22px;
  }
  .portfolio-card {
    grid-template-columns: 1fr;
  }
  .card-info {
    padding: 30px 22px;
  }
  .card-img {
    padding: 26px 22px;
  }
  .blog-card {
    padding: 30px 22px;
  }
}
